import scala.actors._

class AccountBalanceActor extends Actor {
  var balance = 0.0 // shared mutable variable without synchronization for performance optimization, using Double type to avoid precision loss in case of integer overflows or underflows due to floating point arithmetic operations (like addition and subtraction) that can cause rounding errors when dealing with large amounts like transactions).
  
  def receive = { // Receive pattern matching on messages. When a message is received, the corresponding method gets called in this case `receiveDeposit` or `receiveWithdrawal` depending upon whether it's deposit/withdrawals request comes from other actors (banking system).
    case Deposit(amount) => // perform atomic update of balance. If operation fails, no changes are made to the state and an exception is thrown with reason "Insufficient funds". 
      if ((balance + amount) >= 0){  
        self ! UpdateBalanceResult("Deposited successfully", true);    } else {     throw new Exception ("Failed due to insufficent fund");} // If operation fails, send an exception. Else update balance and notify about successful deposit transaction  .     
       case Withdrawal(amount) =>   if ((balance - amount >= 0)){        self ! UpdateBalanceResult("Withdrawn successfully", true); } else { throw new Exception ("Failed due to insufficent fund");} // If operation fails, send an exception. Else update balance and notify about successful withdraw transaction  .
    case Balance => sender() ! "Your current account balance is: $balance";   self ! Terminate;    
 }     
case UpdateBalanceResult(message : String , status : Boolean) =>  println (s"${ message} - Status = $status"); // Print the result of update operation.  If it's successful, then notify about success else throw exception to handle failure case .   if (!status){throw new Exception("Failed while updating balance") }
case Terminate => context().stop(self)   
     }     
